  (1, '168 Innovative', '168 Innovative', NULL, NULL, '168 Innovative', '168 Innovative', '168 Innovative Co., Ltd. เธเธนเนเธเธณเน€เธเนเธฒเนเธฅเธฐเธเธฑเธ”เธเธณเธซเธเนเธฒเธขเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธเธงเธ”เธเธฑเนเธก เธเธฃเธฐเธเธธเธเธเธฃเธตเธก เนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธฅเธฒเธชเธ•เธดเธเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เน OEM เธเธฃเนเธญเธกเธเธฃเธดเธเธฒเธฃเธเธฑเธ”เธซเธฒเธชเธดเธเธเนเธฒเนเธฅเธฐเธเธงเธเธเธธเธกเธเธธเธ“เธ เธฒเธเธเธฒเธเนเธฃเธเธเธฒเธเธเธนเนเธเธฅเธดเธ•', '168 Innovative Co., Ltd. is a trusted importer and distributor of cosmetic packaging and plastic containers for OEM brands, providing high-quality packaging solutions and reliable supply chains.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/logo.png', '168 Innovative', '168 Innovative', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/logo.png', 'th', 'Asia/Bangkok', 'https://line.me/ti/p/~168innovative', 'https://www.facebook.com/profile.php?id=61558620009617', NULL, 'https://shopee.co.th/shop/1240917079');
INSERT INTO `page_seo` (`page_key`, `title_th`, `title_en`, `description_th`, `description_en`, `canonical_path_th`, `canonical_path_en`, `og_image_url`, `og_image_alt_th`, `og_image_alt_en`, `robots_index`, `robots_follow`) VALUES
  ('about', 'เน€เธเธตเนเธขเธงเธเธฑเธเน€เธฃเธฒ | 168 Innovative', 'about us | 168 Innovative', '168 Innovative Co., Ltd. เธเธนเนเธเธณเน€เธเนเธฒเนเธฅเธฐเธเธฑเธ”เธเธณเธซเธเนเธฒเธขเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธเธงเธ”เธเธฑเนเธก เธเธฃเธฐเธเธธเธเธเธฃเธตเธก เนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธฅเธฒเธชเธ•เธดเธเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เน OEM เธเธฃเนเธญเธกเธเธฃเธดเธเธฒเธฃเธเธฑเธ”เธซเธฒเธชเธดเธเธเนเธฒเนเธฅเธฐเธเธงเธเธเธธเธกเธเธธเธ“เธ เธฒเธเธเธฒเธเนเธฃเธเธเธฒเธเธเธนเนเธเธฅเธดเธ•', '168 Innovative Co., Ltd. is a trusted importer and distributor of cosmetic packaging and plastic containers for OEM brands, providing high-quality packaging solutions and reliable supply chains.', 'https://168innovative.co.th/about', 'https://168innovative.co.th/en/about', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/factory.png', 'เธเธฃเธฐเธเธงเธเธเธฒเธฃเธเธฑเธ”เน€เธฅเธทเธญเธเนเธฅเธฐเธ•เธฃเธงเธเธชเธญเธเธเธธเธ“เธ เธฒเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน', 'Warehouse and packaging inventory management system', 1, 1),
  ('category:spout', 'เธเธธเธเธเธญเธ เธเธธเธเธ•เธดเธ”เธเธญเธ เธเธฅเธฒเธชเธ•เธดเธ OEM | 168 Innovative', 'Plastic Spout Caps OEM Manufacturer Thailand | 168 Innovative', 'เธเธธเธเธเธญเธเธเธฅเธฒเธชเธ•เธดเธ เธเธธเธเธ•เธดเธ”เธเธญเธ เธงเธฑเธชเธ”เธธ HDPE เธเธธเธ“เธ เธฒเธเธชเธนเธ \nเน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธญเธฒเธซเธฒเธฃ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธง \nเธฃเธฑเธเธเธฅเธดเธ• OEM/ODM เธเธณเธเธงเธเธกเธฒเธ เธชเนเธเธ—เธฑเนเธงเนเธ—เธขเนเธฅเธฐเธชเนเธเธญเธญเธ \nเธ•เธดเธ”เธ•เนเธญเธเธญเนเธเน€เธชเธเธญเธฃเธฒเธเธฒเนเธ”เนเน€เธฅเธข', 'High-quality HDPE plastic spout caps for cosmetic, food, and \nliquid flexible pouch packaging. OEM/ODM manufacturing. \nBulk orders available. Request a quote today.', 'https://168innovative.co.th/categories/spout', 'https://168innovative.co.th/en/categories/spout', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/sm04.webp', 'เธเธธเธเธเธญเธ', 'Spout Caps', 1, 1),
  ('category:dispensing-press-cap', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” เธชเธณเธซเธฃเธฑเธเธเธงเธ” OEM | 168 Innovative', 'Dispensing Press Cap for Bottles OEM Thailand | 168 Innovative', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธก เนเธฅเธเธฑเนเธ เน€เธเธฅ เนเธเนเธเธฒเธเธเนเธฒเธข เธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เนเธ”เนเนเธกเนเธเธขเธณ เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM เธชเนเธเธ—เธฑเนเธงเนเธ—เธข', 'Dispensing press caps for cream, lotion, and gel bottles. One-handed operation with precise output control. OEM/ODM manufacturing in Thailand. Request a quote.', 'https://168innovative.co.th/categories/dispensing-press-cap', 'https://168innovative.co.th/en/categories/dispensing-press-cap', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/dispensing-cap.webp', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” OEM เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธกเนเธฅเธฐเนเธฅเธเธฑเนเธ', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” OEM เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธกเนเธฅเธฐเนเธฅเธเธฑเนเธ', 1, 1),
  ('category:lipstick-packaging', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ OEM | 168 Innovative', 'Lipstick Packaging & Tube OEM Thailand | 168 Innovative', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ OEM/ODM เธเธธเธ“เธ เธฒเธเธชเธนเธ เธเธฅเธฒเธชเธ•เธดเธเนเธฅเธฐเธญเธฐเธฅเธนเธกเธดเน€เธเธตเธขเธก เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธชเธฑเนเธเธเธณเธเธงเธเธกเธฒเธ', 'Premium lipstick tubes and packaging for OEM/ODM cosmetic brands. Plastic and aluminum options. Custom design manufacturing in Thailand.', 'https://168innovative.co.th/categories/lipstick-packaging', 'https://168innovative.co.th/en/categories/lipstick-packaging', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/lipstick_bottles.webp', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Lipstick Packaging Tube OEM for Cosmetic Brands Thailand', 1, 1),
  ('category:mascara-packaging', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ OEM | 168 Innovative', 'Mascara Packaging & Tube OEM Manufacturer Thailand | 168 Innovative', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ OEM/ODM เธเธธเธ“เธ เธฒเธเธชเธนเธ เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธซเธฅเธฒเธเธซเธฅเธฒเธขเธฃเธนเธเนเธเธ เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ เธชเธฑเนเธเธเธณเธเธงเธเธกเธฒเธ', 'High-quality mascara tubes and packaging for cosmetic OEM/ODM brands. Custom design and manufacturing in Thailand. Multiple styles available.', 'https://168innovative.co.th/categories/mascara-packaging', 'https://168innovative.co.th/en/categories/mascara-packaging', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/mascaras.webp', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Mascara Packaging Tube OEM for Cosmetic Brands Thailand', 1, 1),
  ('category:powder-compact', 'เธ•เธฅเธฑเธเนเธเนเธเธเธฑเธ เธ•เธฅเธฑเธเนเธเนเธ เธเธฅเนเธญเธเนเธเนเธ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ | 168 Innovative', 'Compact Powder Case OEM Cosmetic Packaging | 168 Innovative', 'เธ•เธฅเธฑเธเนเธเนเธ เธเธฅเนเธญเธเนเธเนเธเธเธฑเธ เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ OEM/ODM เธเธธเธ“เธ เธฒเธเธชเธนเธ เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเนเธเนเธเธญเธฑเธ”เนเธเนเธ เธเธฅเธฑเธเธญเธญเธ เนเธฎเนเธฅเธ—เน เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ เธชเธฑเนเธเธเธณเธเธงเธเธกเธฒเธ', 'High-quality compact powder cases for pressed powder, blush, and highlighter. OEM/ODM cosmetic packaging manufacturer in Thailand. Custom design available.', 'https://168innovative.co.th/categories/powder-compact', 'https://168innovative.co.th/en/categories/powder-compact', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/Compact-Powder-Case.webp', 'เธ•เธฅเธฑเธเนเธเนเธ เธเธฅเนเธญเธเนเธเนเธเธเธฑเธ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Compact Powder Case OEM Cosmetic Packaging Thailand', 1, 1),
  ('category:soap-bag', 'เธ–เธธเธเธชเธเธนเน เธ–เธธเธเธเธฃเธฃเธเธธเธชเธเธนเน OEM เธซเธฅเธฒเธเธซเธฅเธฒเธขเธงเธฑเธชเธ”เธธ | 168 Innovative', 'Soap Bag & Bath Product Packaging OEM Thailand | 168 Innovative', 'เธ–เธธเธเธชเธเธนเน เธ–เธธเธเธเธฃเธฃเธเธธเธชเธเธนเนเธเนเธญเธ เธชเธเธนเนเนเธฎเธเธ”เนเน€เธกเธ” เธซเธฅเธฒเธเธซเธฅเธฒเธขเธงเธฑเธชเธ”เธธ เธเนเธฒ เธ•เธฒเธเนเธฒเธข เธเธฅเธฒเธชเธ•เธดเธ เธฃเธฑเธเธเธฅเธดเธ• OEM เธ•เธฒเธกเนเธเธ เธชเธฑเนเธเธเธณเธเธงเธเธกเธฒเธ เธฃเธฒเธเธฒเธชเนเธ', 'Soap bags and bath product packaging in fabric, mesh, and plastic. OEM custom manufacturing for handmade soap and bath brands. Bulk orders available.', 'https://168innovative.co.th/categories/soap-bag', 'https://168innovative.co.th/en/categories/soap-bag', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/soap-bags.png', 'เธ–เธธเธเธชเธเธนเน / เธ–เธธเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน', 'Soap Packaging Bag', 1, 1),
  ('category:ball-chain', 'เนเธเนเธฅเธนเธเธเธฑเธ” Ball Chain เธญเธธเธเธเธฃเธ“เนเน€เธชเธฃเธดเธกเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน OEM | 168 Innovative', 'Ball Chain & Packaging Accessories OEM Thailand | 168 Innovative', 'เนเธเนเธฅเธนเธเธเธฑเธ” ball chain เธญเธธเธเธเธฃเธ“เนเน€เธชเธฃเธดเธกเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน เธชเธดเธเธเนเธฒเธเธฃเธตเน€เธกเธตเธขเธก เธเธญเธเธเธงเธฑเธ เธซเธฅเธฒเธเธซเธฅเธฒเธขเธเธเธฒเธ” เธฃเธฑเธเธเธฅเธดเธ• OEM เธชเนเธเธ—เธฑเนเธงเนเธ—เธข', 'Ball chains and packaging accessories for premium products, gifts, and jewelry. OEM manufacturing in Thailand. Various sizes available. Request a quote.', 'https://168innovative.co.th/categories/ball-chain', 'https://168innovative.co.th/en/categories/ball-chain', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/ball_chain_cat.webp', 'เนเธเนเธฅเธนเธเธเธฑเธ” ball chain เธญเธธเธเธเธฃเธ“เนเน€เธชเธฃเธดเธกเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน OEM', 'Ball Chain Packaging Accessories OEM Thailand', 1, 1),
  ('category:plastic-handle', 'เธ—เธตเนเธเธฑเธเธเธฅเธฒเธชเธ•เธดเธ เธซเธนเธซเธดเนเธง เธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน OEM | 168 Innovative', 'Plastic Handle for Packaging OEM Thailand | 168 Innovative', 'เธ—เธตเนเธเธฑเธเธเธฅเธฒเธชเธ•เธดเธ เธซเธนเธซเธดเนเธงเธเธฅเธฒเธชเธ•เธดเธ เธชเธณเธซเธฃเธฑเธเธ–เธธเธเนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธ—เธธเธเธเธฃเธฐเน€เธ เธ— เธ—เธเธ—เธฒเธ เธเนเธณเธซเธเธฑเธเน€เธเธฒ เธฃเธฑเธเธเธฅเธดเธ• OEM custom size เนเธฅเธฐเธชเธต เธฃเธฒเธเธฒเธชเนเธ', 'Durable plastic handles for bags and packaging. Custom size and color OEM manufacturing available in Thailand. Bulk orders welcome. Request a quote.', 'https://168innovative.co.th/categories/plastic-handle', 'https://168innovative.co.th/en/categories/plastic-handle', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/plastic-handle.webp', 'เธ—เธตเนเธเธฑเธเธเธฅเธฒเธชเธ•เธดเธ เธซเธนเธซเธดเนเธงเธเธฅเธฒเธชเธ•เธดเธเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน OEM', 'Plastic Handle for Packaging OEM Thailand', 1, 1),
