  (86, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/direct_import.png', 'เธฃเธฒเธเธฒเนเธฃเธเธเธฒเธ', 'Factory Price', 'เธฃเธฒเธเธฒเนเธฃเธเธเธฒเธ', 'Factory Price', 'เธเธณเน€เธเนเธฒเนเธ”เธขเธ•เธฃเธ เนเธกเนเธเนเธฒเธเธเธเธเธฅเธฒเธ เธ—เธณเนเธซเนเนเธ”เนเธฃเธฒเธเธฒเธ—เธตเนเธ”เธตเธ—เธตเนเธชเธธเธ”', 'Direct import without middlemen for the best competitive prices.', 1, 1),
  (168, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/quality_standard.png', 'เธเธธเธ“เธ เธฒเธเธเธฃเธตเน€เธกเธตเธขเธก', 'Premium Quality', 'เธเธธเธ“เธ เธฒเธเธเธฃเธตเน€เธกเธตเธขเธก', 'Premium Quality', 'เธเธฑเธ”เธชเธฃเธฃเธงเธฑเธชเธ”เธธ Food Grade เนเธฅเธฐ Cosmetic Grade เธ—เธตเนเธเธฅเธญเธ”เธ เธฑเธข', 'Selection of safe Food Grade and Cosmetic Grade materials.', 2, 1),
  (169, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/oem_support.png', 'เธฃเธญเธเธฃเธฑเธ OEM', 'OEM Support', 'เธฃเธญเธเธฃเธฑเธ OEM', 'OEM Support', 'เธ—เธตเธกเธเธฒเธเน€เธเนเธฒเนเธเธเธงเธฒเธกเธ•เนเธญเธเธเธฒเธฃเธเธญเธเนเธเธฃเธเธ”เน OEM เธญเธขเนเธฒเธเนเธ—เนเธเธฃเธดเธ', 'Our team understands the real needs of OEM brands.', 3, 1),
  (170, 'home', 'why', NULL, 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/reliable_supply.png', 'เธเธฑเธเธเธฅเธฒเธขเน€เธเธเธกเธฑเนเธเธเธ', 'Reliable Supply', 'เธเธฑเธเธเธฅเธฒเธขเน€เธเธเธกเธฑเนเธเธเธ', 'Reliable Supply', 'เธเธงเธเธเธธเธกเธเธธเธ“เธ เธฒเธเนเธฅเธฐเธเธฒเธฃเธเธฑเธ”เธชเนเธเธญเธขเนเธฒเธเน€เธเนเธเธฃเธฐเธเธ เน€เธเธทเนเธญเธเธงเธฒเธกเธ•เนเธญเน€เธเธทเนเธญเธเนเธเธเธฒเธฃเธเธฅเธดเธ•', 'Systematic quality control and logistics for consistent production.', 4, 1);
INSERT INTO `about_sections` (`id`, `section_key`, `eyebrow_th`, `eyebrow_en`, `title_th`, `title_en`, `description_th`, `description_en`, `image_primary_url`, `image_primary_alt_th`, `image_primary_alt_en`, `image_secondary_url`, `image_secondary_alt_th`, `image_secondary_alt_en`, `sort_order`, `is_published`) VALUES
  (1, 'hero', NULL, NULL, 'เธเธณเน€เธเนเธฒเนเธฅเธฐเธเธฑเธ”เธเธณเธซเธเนเธฒเธขเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธฅเธฒเธชเธ•เธดเธเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เน OEM', 'Importer and Distributor of Cosmetic Packaging for OEM Brands and Manufacturers', '168 Innovative Co., Ltd. เนเธซเนเธเธฃเธดเธเธฒเธฃเธเธฑเธ”เธซเธฒเนเธฅเธฐเธเธณเน€เธเนเธฒเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธฅเธฒเธชเธ•เธดเธเธ—เธตเนเธซเธฅเธฒเธเธซเธฅเธฒเธข เน€เธเธทเนเธญเธ•เธญเธเนเธเธ—เธขเนเธเธธเธฃเธเธดเธ OEM เนเธฅเธฐเธเธนเนเธเธฅเธดเธ•เธชเธดเธเธเนเธฒเนเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเธเธงเธฒเธกเธเธฒเธก เนเธ”เธขเธชเธดเธเธเนเธฒเธเธญเธเน€เธฃเธฒเธเธฃเธญเธเธเธฅเธธเธกเธซเธกเธงเธ”เธซเธกเธนเนเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธ—เธตเนเธชเธณเธเธฑเธ เน€เธเนเธ เธเธธเธเธเธญเธเนเธฅเธฐเธญเธธเธเธเธฃเธ“เนเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน เธ•เธฅเธฑเธเนเธเนเธเนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธ–เธธเธเธชเธนเธเธเธฒเธเธฒเธจเนเธฅเธฐเธ–เธธเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน เธ—เธตเนเธเธฑเธเธเธฅเธฒเธชเธ•เธดเธเนเธฅเธฐเธเธดเนเธเธชเนเธงเธเธเธฃเธฐเธเธญเธ เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธเธงเธ”เธเธฑเนเธกเนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธเธฅเธฒเธชเธ•เธดเธ เนเธ—เนเธเธเธญเธชเน€เธกเธ•เธดเธเนเธฅเธฐเธ เธฒเธเธเธฐเธเธฃเธฃเธเธธ เธฃเธงเธกเธ–เธถเธเนเธเนเธฅเธนเธเธเธฑเธ”เนเธฅเธฐเธญเธธเธเธเธฃเธ“เนเน€เธชเธฃเธดเธกเธชเธณเธซเธฃเธฑเธเธเธฒเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน เธ—เธตเธกเธเธฒเธเธเธญเธเน€เธฃเธฒเธกเธธเนเธเน€เธเนเธเธเธฒเธฃเธเธฑเธ”เน€เธฅเธทเธญเธเธชเธดเธเธเนเธฒเธ—เธตเนเธกเธตเธเธธเธ“เธ เธฒเธเธเธฒเธเธเธนเนเธเธฅเธดเธ•เธ—เธตเนเน€เธเธทเนเธญเธ–เธทเธญเนเธ”เน เธเธฃเนเธญเธกเธ—เธฑเนเธเธเธฃเธดเธซเธฒเธฃเธเธฑเธ”เธเธฒเธฃเธเธฅเธฑเธเธชเธดเธเธเนเธฒเนเธฅเธฐเธฃเธฐเธเธเธเธฑเธ”เธชเนเธเธญเธขเนเธฒเธเธกเธตเธเธฃเธฐเธชเธดเธ—เธเธดเธ เธฒเธ เน€เธเธทเนเธญเนเธซเนเธฅเธนเธเธเนเธฒเธชเธฒเธกเธฒเธฃเธ–เน€เธเนเธฒเธ–เธถเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธ—เธตเนเน€เธซเธกเธฒเธฐเธชเธกเธเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเนเธฅเธฐเธเธฒเธฃเธเธฅเธดเธ•เนเธ”เนเธญเธขเนเธฒเธเธ•เนเธญเน€เธเธทเนเธญเธ', '168 Innovative Co., Ltd. provides sourcing and distribution services for a wide range of cosmetic packaging and plastic components designed to support OEM brands and manufacturers in the beauty industry. Our product categories include spout caps and packaging components, compact powder cases and cosmetic containers, vacuum bags and packaging pouches, plastic handles and components, mascara packaging, pump bottles and plastic containers, cosmetic stick containers, as well as ball chains and packaging accessories. We focus on selecting reliable manufacturing partners and maintaining efficient inventory management to ensure a consistent and dependable supply of packaging solutions for our customers.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/factory.png', 'เธเธฃเธฐเธเธงเธเธเธฒเธฃเธเธฑเธ”เน€เธฅเธทเธญเธเนเธฅเธฐเธ•เธฃเธงเธเธชเธญเธเธเธธเธ“เธ เธฒเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน', 'Warehouse and packaging inventory management system', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/warehouse.jpg', 'เธเธฅเธฑเธเธชเธดเธเธเนเธฒเนเธฅเธฐเธฃเธฐเธเธเธเธฑเธ”เธเธฒเธฃเธชเธ•เนเธญเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน', 'เธเธฅเธฑเธเธชเธดเธเธเนเธฒเนเธฅเธฐเธฃเธฐเธเธเธเธฑเธ”เธเธฒเธฃเธชเธ•เนเธญเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน', 1, 1),
  (2, 'who-we-are', NULL, NULL, 'เธเธงเธเน€เธฃเธฒเธเธทเธญเนเธเธฃ', 'Who We Are', 'เน€เธฃเธฒเธกเธตเธเธงเธฒเธกเน€เธเธตเนเธขเธงเธเธฒเธเนเธเธเธฒเธฃเธเธฑเธ”เธชเธฃเธฃเนเธฅเธฐเธเธณเน€เธเนเธฒเธเธดเนเธเธชเนเธงเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธเธฅเธฒเธชเธ•เธดเธเธเธธเธ“เธ เธฒเธเธชเธนเธ เธเธฃเนเธญเธกเธเธฃเธดเธซเธฒเธฃเธเธฑเธ”เธเธฒเธฃเธเธฑเธเธเธฅเธฒเธขเน€เธเธเนเธฅเธฐเธชเธ•เนเธญเธเธชเธดเธเธเนเธฒ เน€เธเธทเนเธญเธฃเธญเธเธฃเธฑเธเธเธงเธฒเธกเธ•เนเธญเธเธเธฒเธฃเธเธญเธเนเธเธฃเธเธ”เน OEM เธญเธขเนเธฒเธเธ•เนเธญเน€เธเธทเนเธญเธเนเธฅเธฐเธกเธฑเนเธเธเธ', 'We specialize in sourcing and importing high-quality plastic packaging components, managing supply chains and inventory to consistently support OEM brands with stability and reliability.', NULL, NULL, NULL, NULL, NULL, NULL, 2, 1);
INSERT INTO `categories` (`id`, `slug`, `name_th`, `name_en`, `description_th`, `description_en`, `intro_html_th`, `intro_html_en`, `seo_title_th`, `seo_title_en`, `seo_description_th`, `seo_description_en`, `image_url`, `image_alt_th`, `image_alt_en`, `sort_order`, `is_published`) VALUES
  (5, 'spout', 'เธเธธเธเธเธญเธ', 'Spout Caps', 'เธเธธเธเธเธญเธ เธเธธเธเธ•เธดเธ”เธเธญเธ เธเธญเธเธ•เธดเธ”เธเธธเธ เนเธฅเธฐเธเธฒเธเธธเธเธเธฅเธฒเธชเธ•เธดเธเธชเธณเธซเธฃเธฑเธเธเธญเธเธเธฃเธฃเธเธธเธเธฃเธตเธก เน€เธเธฅ \nเธเนเธณ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธงเธ—เธธเธเธเธเธดเธ” เธเธฅเธดเธ•เธเธฒเธ HDPE/PE เธเธธเธ“เธ เธฒเธเธชเธนเธ \nเธฃเธญเธเธฃเธฑเธเน€เธเธฃเธทเนเธญเธเธเธฃเธฃเธเธธเธซเธฅเธฒเธเธซเธฅเธฒเธขเธเธฃเธฐเน€เธ เธ— เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM', 'Plastic spout caps for cream, gel, and liquid flexible pouches. \nMade from high-quality HDPE and PE materials. Compatible with \nvarious filling machines. OEM/ODM manufacturing available.', '&lt;h2&gt;เธเธธเธเธเธญเธเธเธฅเธฒเธชเธ•เธดเธ เธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเนเธเธเธเธญเธเธเธฃเธเธงเธเธเธฃ&lt;/h2&gt;\n&lt;p&gt;168 Innovative เธเธนเนเธเธฅเธดเธ•เนเธฅเธฐเธเธณเธซเธเนเธฒเธข &lt;strong&gt;เธเธธเธเธเธญเธ\nเธเธธเธเธ•เธดเธ”เธเธญเธ&lt;/strong&gt; เนเธฅเธฐเธเธฒเธเธธเธเธเธฅเธฒเธชเธ•เธดเธเธเธธเธ“เธ เธฒเธเธชเธนเธ เธชเธณเธซเธฃเธฑเธ\nเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธญเธฒเธซเธฒเธฃ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธงเธ—เธธเธเธเธเธดเธ”\nเธเธฅเธดเธ•เธเธฒเธเธงเธฑเธชเธ”เธธ HDPE เนเธฅเธฐ PE เธเธฅเธญเธ”เธ เธฑเธข เธเธฅเธญเธ”เธชเธฒเธฃ BPA\nเนเธ”เนเธกเธฒเธ•เธฃเธเธฒเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธก&lt;/p&gt;\n\n&lt;h3&gt;เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธฒเธฃเนเธเนเธเธฒเธเนเธ”เธเนเธฒเธ?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธเธญเธเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธเธดเธง (เธเธฃเธตเธก เน€เธเธฅ เน€เธเธฃเธฑเนเธก)&lt;/li&gt;\n&lt;li&gt;เธเธญเธเธเธฃเธฃเธเธธเธญเธฒเธซเธฒเธฃเนเธฅเธฐเน€เธเธฃเธทเนเธญเธเธ”เธทเนเธก (เธเธญเธช เธเนเธณเธเธฅเนเธกเน เธเธก)&lt;/li&gt;\n&lt;li&gt;เธเธญเธเธฃเธตเธเธดเธฅเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ—เธณเธเธงเธฒเธกเธชเธฐเธญเธฒเธ”เนเธเธเนเธฒเธ&lt;/li&gt;\n&lt;li&gt;เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน household chemical เนเธฅเธฐเธชเธฒเธฃเน€เธเธกเธตเน€เธเธฉเธ•เธฃ&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;h3&gt;เธ—เธณเนเธกเธ•เนเธญเธเน€เธฅเธทเธญเธ 168 Innovative?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธงเธฑเธชเธ”เธธ HDPE/PE เธเธธเธ“เธ เธฒเธเธชเธนเธ food-safe เธเธฅเธญเธ”เธชเธฒเธฃ BPA&lt;/li&gt;\n&lt;li&gt;เธฃเธญเธเธฃเธฑเธเน€เธเธฃเธทเนเธญเธเธเธฃเธฃเธเธธเธซเธฅเธฒเธเธซเธฅเธฒเธขเธเธฃเธฐเน€เธ เธ—เนเธฅเธฐเธเธเธฒเธ”&lt;/li&gt;\n&lt;li&gt;เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM เธ•เธฒเธกเนเธเธ custom mold&lt;/li&gt;\n&lt;li&gt;เธฃเธญเธเธฃเธฑเธ private label เนเธฅเธฐเธเธดเธกเธเนเนเธฅเนเธเนเนเธ”เน&lt;/li&gt;\n&lt;li&gt;เธชเธฑเนเธเธเธฅเธดเธ•เธเธณเธเธงเธเธกเธฒเธ เธฃเธฒเธเธฒเธชเนเธ เธชเนเธเธ—เธฑเนเธงเนเธ—เธขเนเธฅเธฐเธชเนเธเธญเธญเธ&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Plastic Spout Caps for Flexible Pouch Packaging&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures and supplies premium\n&lt;strong&gt;plastic spout caps&lt;/strong&gt; for cosmetic, food,\nand liquid flexible packaging industries. All products are\nmade from high-quality HDPE and PE โ€” BPA-free and\nfood-safe certified.&lt;/p&gt;\n\n&lt;h3&gt;Applications&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Cosmetic and skincare pouches (cream, gel, serum)&lt;/li&gt;\n&lt;li&gt;Food and beverage flexible packaging (sauce, juice, dairy)&lt;/li&gt;\n&lt;li&gt;Household cleaning product refill pouches&lt;/li&gt;\n&lt;li&gt;Agricultural and industrial liquid packaging&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;h3&gt;Why Choose 168 Innovative?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;High-quality HDPE/PE โ€” BPA-free and food-safe&lt;/li&gt;\n&lt;li&gt;Compatible with various filling machines and pouch sizes&lt;/li&gt;\n&lt;li&gt;OEM/ODM custom mold production available&lt;/li&gt;\n&lt;li&gt;Private label and logo printing supported&lt;/li&gt;\n&lt;li&gt;Bulk orders welcome โ€” serving Thailand and export markets&lt;/li&gt;\n&lt;/ul&gt;', 'เธเธธเธเธเธญเธ เธเธธเธเธ•เธดเธ”เธเธญเธ เธเธฅเธฒเธชเธ•เธดเธ OEM | 168 Innovative', 'Plastic Spout Caps OEM Manufacturer Thailand | 168 Innovative', 'เธเธธเธเธเธญเธเธเธฅเธฒเธชเธ•เธดเธ เธเธธเธเธ•เธดเธ”เธเธญเธ เธงเธฑเธชเธ”เธธ HDPE เธเธธเธ“เธ เธฒเธเธชเธนเธ \nเน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธญเธฒเธซเธฒเธฃ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธง \nเธฃเธฑเธเธเธฅเธดเธ• OEM/ODM เธเธณเธเธงเธเธกเธฒเธ เธชเนเธเธ—เธฑเนเธงเนเธ—เธขเนเธฅเธฐเธชเนเธเธญเธญเธ \nเธ•เธดเธ”เธ•เนเธญเธเธญเนเธเน€เธชเธเธญเธฃเธฒเธเธฒเนเธ”เนเน€เธฅเธข', 'High-quality HDPE plastic spout caps for cosmetic, food, and \nliquid flexible pouch packaging. OEM/ODM manufacturing. \nBulk orders available. Request a quote today.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/spout.webp', 'เธเธธเธเธเธญเธ', 'Spout Caps', 5, 1),
  (6, 'dispensing-press-cap', 'เธเธฒเธเธฅเธฒเธชเธ•เธดเธ เธเธฒเธเธ”', 'Dispensing Press Cap', 'เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” เธเธฒเธเธ” เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธก เนเธฅเธเธฑเนเธ เน€เธเธฅ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธง เนเธเนเธเธฒเธเธเนเธฒเธขเธ”เนเธงเธขเธกเธทเธญเน€เธ”เธตเธขเธง เธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เนเธ”เนเนเธกเนเธเธขเธณ เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM', 'Dispensing press caps for cream, lotion, gel, and liquid bottles. Easy one-handed operation with precise dispensing control. OEM/ODM manufacturing available.', '&lt;h2&gt;เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เน&lt;/h2&gt;\n&lt;p&gt;168 Innovative เธเธณเธซเธเนเธฒเธขเนเธฅเธฐเธฃเธฑเธเธเธฅเธดเธ• &lt;strong&gt;เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ”&lt;/strong&gt; เธเธธเธ“เธ เธฒเธเธชเธนเธ เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธก เนเธฅเธเธฑเนเธ เน€เธเธฅ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธงเธ—เธธเธเธเธเธดเธ” เธญเธญเธเนเธเธเธกเธฒเน€เธเธทเนเธญเธเธฒเธฃเนเธเนเธเธฒเธเธเนเธฒเธขเธ”เนเธงเธขเธกเธทเธญเน€เธ”เธตเธขเธง เธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เนเธ”เนเนเธกเนเธเธขเธณ เนเธกเนเธซเธขเธ”&lt;/p&gt;\n&lt;h3&gt;เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเนเธ”เธเนเธฒเธ?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธเธฃเธตเธกเธเธณเธฃเธธเธเธเธดเธงเนเธฅเธฐ body lotion&lt;/li&gt;\n&lt;li&gt;เน€เธเธฅเธฅเนเธฒเธเธกเธทเธญเนเธฅเธฐ hand cream&lt;/li&gt;\n&lt;li&gt;เนเธเธกเธเธนเนเธฅเธฐเธเธฃเธตเธกเธเธงเธ”เธเธก&lt;/li&gt;\n&lt;li&gt;เธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ—เธณเธเธงเธฒเธกเธชเธฐเธญเธฒเธ”เนเธเธเนเธฒเธ&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;เธเธธเธ”เน€เธ”เนเธ&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เนเธเนเธเธฒเธเธเนเธฒเธขเธ”เนเธงเธขเธกเธทเธญเน€เธ”เธตเธขเธง one-handed operation&lt;/li&gt;\n&lt;li&gt;เธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เนเธ”เนเนเธกเนเธเธขเธณ เนเธกเนเธซเธขเธ” เนเธกเนเน€เธฅเธญเธฐ&lt;/li&gt;\n&lt;li&gt;เธงเธฑเธชเธ”เธธเธเธฅเธฒเธชเธ•เธดเธเธเธธเธ“เธ เธฒเธเธชเธนเธ เธ—เธเธ—เธฒเธ&lt;/li&gt;\n&lt;li&gt;เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM custom size เนเธฅเธฐเธชเธต&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Dispensing Press Caps for Liquid Packaging&lt;/h2&gt;\n&lt;p&gt;168 Innovative supplies and manufactures &lt;strong&gt;dispensing press caps&lt;/strong&gt; for cream, lotion, gel, and liquid bottles. Designed for easy one-handed operation with precise, drip-free dispensing control.&lt;/p&gt;\n&lt;h3&gt;Suitable Products&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Skin cream and body lotion&lt;/li&gt;\n&lt;li&gt;Hand gel and hand cream&lt;/li&gt;\n&lt;li&gt;Shampoo and conditioner&lt;/li&gt;\n&lt;li&gt;Household cleaning products&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;Key Features&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Easy one-handed operation&lt;/li&gt;\n&lt;li&gt;Precise dispensing โ€” drip-free and mess-free&lt;/li&gt;\n&lt;li&gt;High-quality durable plastic&lt;/li&gt;\n&lt;li&gt;OEM/ODM custom size and color available&lt;/li&gt;\n&lt;/ul&gt;', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” เธชเธณเธซเธฃเธฑเธเธเธงเธ” OEM | 168 Innovative', 'Dispensing Press Cap for Bottles OEM Thailand | 168 Innovative', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธก เนเธฅเธเธฑเนเธ เน€เธเธฅ เนเธเนเธเธฒเธเธเนเธฒเธข เธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เนเธ”เนเนเธกเนเธเธขเธณ เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM เธชเนเธเธ—เธฑเนเธงเนเธ—เธข', 'Dispensing press caps for cream, lotion, and gel bottles. One-handed operation with precise output control. OEM/ODM manufacturing in Thailand. Request a quote.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/03/dispensing-cap.webp', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” OEM เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธกเนเธฅเธฐเนเธฅเธเธฑเนเธ', 'เธเธฒเธเธ” เธเธฒเธเธฅเธฒเธชเธ•เธดเธเนเธเธเธเธ” OEM เธชเธณเธซเธฃเธฑเธเธเธงเธ”เธเธฃเธตเธกเนเธฅเธฐเนเธฅเธเธฑเนเธ', 6, 1),
  (7, 'lipstick-packaging', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ', 'Lipstick Packaging', 'เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ OEM/ODM เธซเธฅเธฒเธเธซเธฅเธฒเธขเธงเธฑเธชเธ”เธธเนเธฅเธฐเธฃเธนเธเนเธเธ เธ—เธฑเนเธเธเธฅเธฒเธชเธ•เธดเธเนเธฅเธฐเธญเธฐเธฅเธนเธกเธดเน€เธเธตเธขเธก เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ', 'Lipstick tubes and packaging for cosmetic brands. OEM/ODM manufacturing in plastic and aluminum. Custom design available.', '&lt;h2&gt;เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ&lt;/h2&gt;\n&lt;p&gt;168 Innovative เธเธนเนเธเธฅเธดเธ• &lt;strong&gt;เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ เนเธฅเธฐเนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ&lt;/strong&gt; เธเธธเธ“เธ เธฒเธเธชเธนเธ เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เน OEM/ODM เธกเธตเธ—เธฑเนเธเธงเธฑเธชเธ”เธธเธเธฅเธฒเธชเธ•เธดเธเนเธฅเธฐเธญเธฐเธฅเธนเธกเธดเน€เธเธตเธขเธก เธซเธฅเธฒเธเธซเธฅเธฒเธขเธฃเธนเธเนเธเธ เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธงเธฒเธกเธซเธฃเธนเธซเธฃเธฒเธซเธฃเธทเธญ eco-friendly&lt;/p&gt;\n&lt;h3&gt;เธงเธฑเธชเธ”เธธเธ—เธตเนเธกเธตเนเธซเนเน€เธฅเธทเธญเธ&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธเธฅเธฒเธชเธ•เธดเธ ABS โ€” เธเนเธณเธซเธเธฑเธเน€เธเธฒ เธฃเธฒเธเธฒเธเธฃเธฐเธซเธขเธฑเธ” เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธ mass market&lt;/li&gt;\n&lt;li&gt;เธญเธฐเธฅเธนเธกเธดเน€เธเธตเธขเธก โ€” เธเธฃเธตเน€เธกเธตเธขเธก เธ—เธเธ—เธฒเธ เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธ luxury brand&lt;/li&gt;\n&lt;li&gt;Recycled plastic โ€” เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธ eco-conscious brand&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;เธเธฃเธดเธเธฒเธฃ OEM/ODM&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom design เธ—เธฑเนเธ shape, size เนเธฅเธฐ mechanism&lt;/li&gt;\n&lt;li&gt;เน€เธฅเธทเธญเธ finish เนเธ”เน matte, glossy, metallic&lt;/li&gt;\n&lt;li&gt;เธเธดเธกเธเนเนเธฅเนเธเนเนเธฅเธฐ hot stamping&lt;/li&gt;\n&lt;li&gt;MOQ เธขเธทเธ”เธซเธขเธธเนเธ เน€เธซเธกเธฒเธฐเธ—เธฑเนเธเนเธเธฃเธเธ”เนเนเธซเธกเนเนเธฅเธฐเนเธเธฃเธเธ”เนเนเธซเธเน&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Lipstick Packaging OEM for Cosmetic Brands&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures premium &lt;strong&gt;lipstick tubes and packaging&lt;/strong&gt; for OEM/ODM brands. Available in plastic and aluminum โ€” suitable for mass market, luxury, and eco-conscious brands.&lt;/p&gt;\n&lt;h3&gt;Available Materials&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;ABS Plastic โ€” lightweight, cost-effective, ideal for mass market&lt;/li&gt;\n&lt;li&gt;Aluminum โ€” premium, durable, ideal for luxury brands&lt;/li&gt;\n&lt;li&gt;Recycled plastic โ€” ideal for eco-conscious brands&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;OEM/ODM Services&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom shape, size, and mechanism design&lt;/li&gt;\n&lt;li&gt;Matte, glossy, and metallic finish options&lt;/li&gt;\n&lt;li&gt;Logo printing and hot stamping available&lt;/li&gt;\n&lt;li&gt;Flexible MOQ for new and established brands&lt;/li&gt;\n&lt;/ul&gt;', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ OEM | 168 Innovative', 'Lipstick Packaging & Tube OEM Thailand | 168 Innovative', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ OEM/ODM เธเธธเธ“เธ เธฒเธเธชเธนเธ เธเธฅเธฒเธชเธ•เธดเธเนเธฅเธฐเธญเธฐเธฅเธนเธกเธดเน€เธเธตเธขเธก เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธชเธฑเนเธเธเธณเธเธงเธเธกเธฒเธ', 'Premium lipstick tubes and packaging for OEM/ODM cosmetic brands. Plastic and aluminum options. Custom design manufacturing in Thailand.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/lipstick_bottles.webp', 'เนเธเนเธเน€เธเธเธฅเธดเธเธชเธ•เธดเธ เธซเธฅเธญเธ”เธฅเธดเธเธชเธ•เธดเธ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Lipstick Packaging Tube OEM for Cosmetic Brands Thailand', 7, 1),
  (8, 'mascara-packaging', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ', 'Mascara Packaging', 'เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ OEM/ODM เธเธธเธ“เธ เธฒเธเธชเธนเธ เธซเธฅเธฒเธเธซเธฅเธฒเธขเธฃเธนเธเนเธเธเนเธฅเธฐเธเธเธฒเธ” เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ', 'Mascara tubes and packaging for cosmetic brands. OEM/ODM manufacturing with various styles and sizes. Custom design available.', '&lt;h2&gt;เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ&lt;/h2&gt;\n&lt;p&gt;168 Innovative เธเธนเนเธเธฅเธดเธ• &lt;strong&gt;เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ&lt;/strong&gt; เธเธธเธ“เธ เธฒเธเธชเธนเธเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เน OEM/ODM เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ เธซเธฅเธฒเธเธซเธฅเธฒเธขเธฃเธนเธเธ—เธฃเธเนเธฅเธฐเธเธเธฒเธ” เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเนเธซเธกเนเนเธฅเธฐเนเธเธฃเธเธ”เนเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃ private label&lt;/p&gt;\n&lt;h3&gt;เธเธฃเธฐเน€เธ เธ—เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธ—เธตเนเธกเธต&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒเนเธเธเธกเธฒเธ•เธฃเธเธฒเธ (Standard Mascara Tube)&lt;/li&gt;\n&lt;li&gt;เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒเนเธเธ slim เธชเธณเธซเธฃเธฑเธ travel size&lt;/li&gt;\n&lt;li&gt;เธซเธฅเธญเธ”เธเธฃเนเธญเธกเนเธเธฃเธ wand เธซเธฅเธฒเธเธซเธฅเธฒเธขเธฃเธนเธเนเธเธ&lt;/li&gt;\n&lt;li&gt;Custom design เธ•เธฒเธกเนเธเธเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃ&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;เธเธฃเธดเธเธฒเธฃ OEM/ODM&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธญเธญเธเนเธเธเนเธฅเธฐเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ&lt;/li&gt;\n&lt;li&gt;เน€เธฅเธทเธญเธเธชเธตเนเธฅเธฐ finish เนเธ”เนเธ•เธฒเธก brand&lt;/li&gt;\n&lt;li&gt;เธเธดเธกเธเนเนเธฅเนเธเนเนเธฅเธฐ branding เธเธฃเธเธงเธเธเธฃ&lt;/li&gt;\n&lt;li&gt;MOQ เธขเธทเธ”เธซเธขเธธเนเธ เน€เธซเธกเธฒเธฐเธ—เธฑเนเธเนเธเธฃเธเธ”เนเนเธซเธกเนเนเธฅเธฐเนเธเธฃเธเธ”เนเนเธซเธเน&lt;/li&gt;\n&lt;/ul&gt;', '&lt;h2&gt;Mascara Packaging OEM for Cosmetic Brands&lt;/h2&gt;\n&lt;p&gt;168 Innovative manufactures premium &lt;strong&gt;mascara tubes and packaging&lt;/strong&gt; for OEM/ODM cosmetic brands. Custom design, multiple shapes and sizes available โ€” ideal for new brands and private label products.&lt;/p&gt;\n&lt;h3&gt;Available Packaging Types&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Standard mascara tubes&lt;/li&gt;\n&lt;li&gt;Slim tubes for travel size products&lt;/li&gt;\n&lt;li&gt;Various wand and brush styles&lt;/li&gt;\n&lt;li&gt;Fully custom design on request&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;OEM/ODM Services&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;Custom design and mold production&lt;/li&gt;\n&lt;li&gt;Color and finish selection&lt;/li&gt;\n&lt;li&gt;Logo printing and full branding&lt;/li&gt;\n&lt;li&gt;Flexible MOQ for new and established brands&lt;/li&gt;\n&lt;/ul&gt;', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ OEM | 168 Innovative', 'Mascara Packaging & Tube OEM Manufacturer Thailand | 168 Innovative', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ OEM/ODM เธเธธเธ“เธ เธฒเธเธชเธนเธ เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธซเธฅเธฒเธเธซเธฅเธฒเธขเธฃเธนเธเนเธเธ เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ เธชเธฑเนเธเธเธณเธเธงเธเธกเธฒเธ', 'High-quality mascara tubes and packaging for cosmetic OEM/ODM brands. Custom design and manufacturing in Thailand. Multiple styles available.', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/mascaras.webp', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธชเธเธฒเธฃเนเธฒ เธซเธฅเธญเธ”เธกเธฒเธชเธเธฒเธฃเนเธฒ OEM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Mascara Packaging Tube OEM for Cosmetic Brands Thailand', 8, 1),
  (9, 'powder-compact', 'เธ•เธฅเธฑเธเนเธเนเธ', 'Compact Powder Case', 'เธ•เธฅเธฑเธเนเธเนเธ เธเธฅเนเธญเธเนเธเนเธเธเธฑเธ เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเธชเธณเธซเธฃเธฑเธเนเธเนเธเธญเธฑเธ”เนเธเนเธ เนเธเนเธเธเธฑเธ เนเธฅเธฐเนเธฎเนเธฅเธ—เน เธฃเธฑเธเธเธฅเธดเธ• OEM/ODM เธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Compact powder cases and cosmetic packaging for pressed powder, blush, and highlighter. OEM/ODM manufacturing for cosmetic brands.', '&lt;h2&gt;เธ•เธฅเธฑเธเนเธเนเธ เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ OEM&lt;/h2&gt;\n&lt;p&gt;168 Innovative เธเธนเนเธเธฅเธดเธ• &lt;strong&gt;เธ•เธฅเธฑเธเนเธเนเธ เธเธฅเนเธญเธเนเธเนเธเธเธฑเธ&lt;/strong&gt; เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเธเธธเธ“เธ เธฒเธเธชเธนเธ เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเนเธเธฃเธเธ”เนเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธชเธฃเนเธฒเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเนเธเธเธฒเธก OEM/ODM เธฃเธฑเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ custom design เธเธฃเธเธงเธเธเธฃ&lt;/p&gt;\n&lt;h3&gt;เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเนเธ”เธเนเธฒเธ?&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เนเธเนเธเธญเธฑเธ”เนเธเนเธ (Pressed Powder)&lt;/li&gt;\n&lt;li&gt;เธเธฅเธฑเธเธญเธญเธเนเธฅเธฐเนเธฎเนเธฅเธ—เน (Blush / Highlighter)&lt;/li&gt;\n&lt;li&gt;เธญเธฒเธขเนเธเนเธ”เธงเนเธเธฒเน€เธฅเธ— (Eyeshadow Palette)&lt;/li&gt;\n&lt;li&gt;เนเธเนเธเธเธฑเธเธชเธณเธซเธฃเธฑเธเน€เธ”เนเธเนเธฅเธฐเธเธนเนเนเธซเธเน&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h3&gt;เธเธฃเธดเธเธฒเธฃ OEM/ODM เธเธฃเธเธงเธเธเธฃ&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;เธญเธญเธเนเธเธเนเธฅเธฐเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃ&lt;/li&gt;\n&lt;li&gt;เน€เธฅเธทเธญเธเธงเธฑเธชเธ”เธธ เธชเธต เนเธฅเธฐ finish เนเธ”เนเธซเธฅเธฒเธเธซเธฅเธฒเธข&lt;/li&gt;\n&lt;li&gt;เธฃเธญเธเธฃเธฑเธ private label เนเธฅเธฐเธเธด