  (999999, 'uncategorized-migrated', 'เธชเธดเธเธเนเธฒเธฃเธญเธเธฑเธ”เธซเธกเธงเธ”', 'Uncategorized Migrated Products', 'เธซเธกเธงเธ”เธเธฑเนเธงเธเธฃเธฒเธงเธชเธณเธซเธฃเธฑเธเธชเธดเธเธเนเธฒเธ—เธตเนเธกเธตเธญเธขเธนเนเนเธ WordPress dump เนเธ•เนเธขเธฑเธเนเธกเนเนเธ”เนเธเธนเธ product_category', 'Temporary category for products found in the WordPress dump without a mapped product_category relation.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 999999, 1);
INSERT INTO `products` (`id`, `category_id`, `slug`, `name_th`, `name_en`, `family_name_th`, `family_name_en`, `description_th`, `description_en`, `content_th`, `content_en`, `application_th`, `application_en`, `seo_title_th`, `seo_title_en`, `seo_description_th`, `seo_description_en`, `image_url`, `image_alt_th`, `image_alt_en`, `sku`, `availability_status`, `moq`, `lead_time`, `default_variant_slug`, `sort_order`, `is_published`) VALUES
  (463, 5, 'plastic-spout-hl018-1-8mm', 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL018 เธเธเธฒเธ” 1.8 เธกเธก.', 'Plastic Spout HL018 1.8mm', NULL, NULL, 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL018 เธเธฅเธดเธ•เธเธฒเธเธงเธฑเธชเธ”เธธ PE เธเธธเธ“เธ เธฒเธเธชเธนเธ เธกเธตเน€เธชเนเธเธเนเธฒเธเธจเธนเธเธขเนเธเธฅเธฒเธเธ เธฒเธขเนเธ 1.8 เธกเธก. เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธเธฒเธกเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฒเธฃเธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เธเธญเธเน€เธซเธฅเธงเธญเธขเนเธฒเธเนเธกเนเธเธขเธณ เธเธธเธเธเธเธฒเธ”เน€เธฅเนเธเธเธดเน€เธจเธฉเธเธตเนเธญเธญเธเนเธเธเธกเธฒเน€เธเธทเนเธญเธฃเธญเธเธฃเธฑเธเธเธญเธเธฃเธตเธเธดเธฅ เธเธญเธเธเธฃเธฃเธเธธเธเธญเธเน€เธซเธฅเธง เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเนเธเธ pouch เธชเธณเธซเธฃเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธซเธเธทเธ”เธชเธนเธ เธงเธฑเธชเธ”เธธ PE เธ—เธตเนเนเธเนเธเธฅเธดเธ•เธกเธตเธเธงเธฒเธกเธขเธทเธ”เธซเธขเธธเนเธ เธ—เธเธ—เธฒเธเธ•เนเธญเธชเธฒเธฃเน€เธเธกเธต เนเธฅเธฐเธเธฅเธญเธ”เธ เธฑเธขเธชเธณเธซเธฃเธฑเธเธเธฒเธฃเธชเธฑเธกเธเธฑเธชเธเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธเธดเธง เน€เธเธฅ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธงเน€เธเนเธกเธเนเธ เน€เธซเธกเธฒเธฐเธเธฑเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธขเธฒ เนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธชเนเธงเธเธ•เธฑเธง เธ•เธญเธเนเธเธ—เธขเนเธเธนเนเธเธฅเธดเธ•เธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธ•เธฃเธเธฒเธเธชเธนเธเนเธเธฃเธฒเธเธฒเธ—เธตเนเนเธเนเธเธเธฑเธเนเธ”เน', 'The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensing in cosmetic and beauty packaging. This small-size spout cap is ideal for refill pouches, liquid pouch packaging, and cosmetic applications where controlled flow is essential. The PE construction ensures chemical resistance, flexibility, and compatibility with a wide range of beauty formulations including serums, gels, and concentrated liquids. Designed for B2B packaging suppliers and cosmetic manufacturers seeking reliable, high-precision spout solutions, the HL018 meets stringent quality standards for personal care and pharmaceutical pouch packaging. Its compact design makes it a preferred choice for travel-size and sample packaging formats.', '<p>เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL018 เธเธฅเธดเธ•เธเธฒเธเธงเธฑเธชเธ”เธธ PE เธเธธเธ“เธ เธฒเธเธชเธนเธ เธกเธตเน€เธชเนเธเธเนเธฒเธเธจเธนเธเธขเนเธเธฅเธฒเธเธ เธฒเธขเนเธ 1.8 เธกเธก. เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธเธฒเธกเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฒเธฃเธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เธเธญเธเน€เธซเธฅเธงเธญเธขเนเธฒเธเนเธกเนเธเธขเธณ เธเธธเธเธเธเธฒเธ”เน€เธฅเนเธเธเธดเน€เธจเธฉเธเธตเนเธญเธญเธเนเธเธเธกเธฒเน€เธเธทเนเธญเธฃเธญเธเธฃเธฑเธเธเธญเธเธฃเธตเธเธดเธฅ เธเธญเธเธเธฃเธฃเธเธธเธเธญเธเน€เธซเธฅเธง เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเนเธเธ pouch เธชเธณเธซเธฃเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธซเธเธทเธ”เธชเธนเธ เธงเธฑเธชเธ”เธธ PE เธ—เธตเนเนเธเนเธเธฅเธดเธ•เธกเธตเธเธงเธฒเธกเธขเธทเธ”เธซเธขเธธเนเธ เธ—เธเธ—เธฒเธเธ•เนเธญเธชเธฒเธฃเน€เธเธกเธต เนเธฅเธฐเธเธฅเธญเธ”เธ เธฑเธขเธชเธณเธซเธฃเธฑเธเธเธฒเธฃเธชเธฑเธกเธเธฑเธชเธเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธเธดเธง เน€เธเธฅ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธงเน€เธเนเธกเธเนเธ เน€เธซเธกเธฒเธฐเธเธฑเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธขเธฒ เนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธชเนเธงเธเธ•เธฑเธง เธ•เธญเธเนเธเธ—เธขเนเธเธนเนเธเธฅเธดเธ•เธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธ•เธฃเธเธฒเธเธชเธนเธเนเธเธฃเธฒเธเธฒเธ—เธตเนเนเธเนเธเธเธฑเธเนเธ”เน</p>', '<p>The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensing in cosmetic and beauty packaging. This small-size spout cap is ideal for refill pouches, liquid pouch packaging, and cosmetic applications where controlled flow is essential. The PE construction ensures chemical resistance, flexibility, and compatibility with a wide range of beauty formulations including serums, gels, and concentrated liquids. Designed for B2B packaging suppliers and cosmetic manufacturers seeking reliable, high-precision spout solutions, the HL018 meets stringent quality standards for personal care and pharmaceutical pouch packaging. Its compact design makes it a preferred choice for travel-size and sample packaging formats.</p>', 'เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ, เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธเธฒเธก, เธเธญเธเธเธฃเธฃเธเธธเธเธญเธเน€เธซเธฅเธง, เธเธญเธเธฃเธตเธเธดเธฅ', 'Cosmetic Packaging, Beauty Packaging, Liquid Pouch, Refill Pouch', 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL018 เธเธเธฒเธ” 1.8 เธกเธก. | เธชเธณเธซเธฃเธฑเธเธเธญเธเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ | OEM', 'Plastic Spout HL018 1.8mm | Cosmetic Packaging OEM / ODM', 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL018 เธเธฅเธดเธ•เธเธฒเธเธงเธฑเธชเธ”เธธ PE เธเธธเธ“เธ เธฒเธเธชเธนเธ เธกเธตเน€เธชเนเธเธเนเธฒเธเธจเธนเธเธขเนเธเธฅเธฒเธเธ เธฒเธขเนเธ 1.8 เธกเธก. เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธเธฒเธกเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฒเธฃเธเธงเธเธเธธเธกเธเธฃเธดเธกเธฒเธ“เธเธญเธเน€เธซเธฅเธงเธญเธขเนเธฒเธเนเธกเนเธเธขเธณ เธเธธเธเธเธเธฒเธ”เน€เธฅเนเธเธเธดเน€เธจเธฉเธเธตเนเธญเธญเธเนเธเธเธกเธฒเน€เธเธทเนเธญเธฃเธญเธเธฃเธฑเธเธเธญเธเธฃเธตเธเธดเธฅ เธเธญเธเธเธฃเธฃเธเธธเธเธญเธเน€เธซเธฅเธง เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเนเธเธ pouch เธชเธณเธซเธฃเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธซเธเธทเธ”เธชเธนเธ เธงเธฑเธชเธ”เธธ PE เธ—เธตเนเนเธเนเธเธฅเธดเธ•เธกเธตเธเธงเธฒเธกเธขเธทเธ”เธซเธขเธธเนเธ เธ—เธเธ—เธฒเธเธ•เนเธญเธชเธฒเธฃเน€เธเธกเธต เนเธฅเธฐเธเธฅเธญเธ”เธ เธฑเธขเธชเธณเธซเธฃเธฑเธเธเธฒเธฃเธชเธฑเธกเธเธฑเธชเธเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธเธดเธง เน€เธเธฅ เนเธฅเธฐเธเธญเธเน€เธซเธฅเธงเน€เธเนเธกเธเนเธ เน€เธซเธกเธฒเธฐเธเธฑเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ เธขเธฒ เนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธ”เธนเนเธฅเธชเนเธงเธเธ•เธฑเธง เธ•เธญเธเนเธเธ—เธขเนเธเธนเนเธเธฅเธดเธ•เธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธกเธฒเธ•เธฃเธเธฒเธเธชเธนเธเนเธเธฃเธฒเธเธฒเธ—เธตเนเนเธเนเธเธเธฑเธเนเธ”เน เธฃเธธเนเธ HL018 เธเธเธฒเธ” 1.8 เธกเธก. เธงเธฑเธชเธ”เธธ PE เธเธฃเนเธญเธกเธเธฃเธดเธเธฒเธฃ OEM / ODM เธเธฃเธเธงเธเธเธฃ เธชเธฑเนเธเธเธฅเธดเธ•เธ•เธฒเธกเนเธเธ เธฃเธฑเธเธเธฅเธดเธ•เธเธณเธเธงเธเธกเธฒเธ', 'The HL018 plastic spout features an ultra-small inner diameter of 1.8mm, manufactured from high-quality PE material suitable for precision liquid dispensin...', 'https://wb.168innovative.co.th/wp-content/uploads/2026/02/HL018.jpg', 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL018 เธเธเธฒเธ” 1.8 เธกเธก. PE เธชเธณเธซเธฃเธฑเธเธเธญเธเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธ', 'Plastic Spout HL018 1.8mm PE for Cosmetic Pouch Packaging', NULL, NULL, NULL, NULL, NULL, 463, 1),
  (464, 5, 'plastic-spout-hl020-2mm', 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL020 เธเธเธฒเธ” 2 เธกเธก.', 'Plastic Spout HL020 2mm', NULL, NULL, 'เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL020 เธเธฅเธดเธ•เธเธฒเธ PE เธเธธเธ“เธ เธฒเธเธชเธนเธ เธกเธตเน€เธชเนเธเธเนเธฒเธเธจเธนเธเธขเนเธเธฅเธฒเธเธ เธฒเธขเนเธ 2 เธกเธก. เธญเธญเธเนเธเธเธกเธฒเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธเธฒเธกเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฒเธฃเธเนเธฒเธขเธเธญเธเน€เธซเธฅเธงเนเธเธเธฃเธดเธกเธฒเธ“เธเนเธญเธขเนเธฅเธฐเนเธกเนเธเธขเธณ เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธญเธเธฃเธตเธเธดเธฅ เธเธญเธเธเธฃเธฃเธเธธเธเธญเธเน€เธซเธฅเธง เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเนเธเธ pouch เธ—เธตเนเนเธเนเนเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเธเธงเธฒเธกเธเธฒเธกเนเธฅเธฐเธเธฒเธฃเธ”เธนเนเธฅเธชเนเธงเธเธ•เธฑเธง เธงเธฑเธชเธ”เธธ PE เธกเธตเธเธงเธฒเธกเธ—เธเธ—เธฒเธเธชเธนเธ เธเธฅเธญเธ”เธ เธฑเธขเธ•เนเธญเธเธฒเธฃเธชเธฑเธกเธเธฑเธชเธเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธซเธฅเธฒเธเธซเธฅเธฒเธขเธเธฃเธฐเน€เธ เธ— เนเธฅเธฐเธชเธฒเธกเธฒเธฃเธ–เธเธฅเธดเธ•เนเธเธเธฃเธดเธกเธฒเธ“เธกเธฒเธเนเธ”เนเธ•เธฒเธกเธกเธฒเธ•เธฃเธเธฒเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธก เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธนเนเธเธฅเธดเธ•เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเนเธเธฅเธนเธเธฑเนเธเธเธธเธ“เธ เธฒเธเธชเธนเธเนเธเธฃเธฒเธเธฒเธ—เธตเนเน€เธซเธกเธฒเธฐเธชเธก', 'The HL020 plastic spout cap with a 2mm inner diameter is crafted from premium PE material, delivering precise liquid dispensing for cosmetic and beauty packaging applications. This small-size spout is engineered for refill pouch packaging, liquid pouches, and beauty product containers requiring fine flow control. The PE material provides excellent chemical resistance and durability, making it compatible with serums, essences, and other personal care formulations. Ideal for B2B cosmetic packaging suppliers and contract manufacturers, the HL020 offers consistent performance in high-volume production environments. Its compact design suits sample pouches, travel-size packaging, and precision dosage applications across cosmetic, pharmaceutical, and personal care industries.', '<p>เธเธธเธเธเธฅเธฒเธชเธ•เธดเธ HL020 เธเธฅเธดเธ•เธเธฒเธ PE เธเธธเธ“เธ เธฒเธเธชเธนเธ เธกเธตเน€เธชเนเธเธเนเธฒเธเธจเธนเธเธขเนเธเธฅเธฒเธเธ เธฒเธขเนเธ 2 เธกเธก. เธญเธญเธเนเธเธเธกเธฒเธชเธณเธซเธฃเธฑเธเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเน€เธเธฃเธทเนเธญเธเธชเธณเธญเธฒเธเนเธฅเธฐเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธเธงเธฒเธกเธเธฒเธกเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเธเธฒเธฃเธเนเธฒเธขเธเธญเธเน€เธซเธฅเธงเนเธเธเธฃเธดเธกเธฒเธ“เธเนเธญเธขเนเธฅเธฐเนเธกเนเธเธขเธณ เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธญเธเธฃเธตเธเธดเธฅ เธเธญเธเธเธฃเธฃเธเธธเธเธญเธเน€เธซเธฅเธง เนเธฅเธฐเธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเนเธเธ pouch เธ—เธตเนเนเธเนเนเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธกเธเธงเธฒเธกเธเธฒเธกเนเธฅเธฐเธเธฒเธฃเธ”เธนเนเธฅเธชเนเธงเธเธ•เธฑเธง เธงเธฑเธชเธ”เธธ PE เธกเธตเธเธงเธฒเธกเธ—เธเธ—เธฒเธเธชเธนเธ เธเธฅเธญเธ”เธ เธฑเธขเธ•เนเธญเธเธฒเธฃเธชเธฑเธกเธเธฑเธชเธเธฑเธเธเธฅเธดเธ•เธ เธฑเธ“เธ‘เนเธซเธฅเธฒเธเธซเธฅเธฒเธขเธเธฃเธฐเน€เธ เธ— เนเธฅเธฐเธชเธฒเธกเธฒเธฃเธ–เธเธฅเธดเธ•เนเธเธเธฃเธดเธกเธฒเธ“เธกเธฒเธเนเธ”เนเธ•เธฒเธกเธกเธฒเธ•เธฃเธเธฒเธเธญเธธเธ•เธชเธฒเธซเธเธฃเธฃเธก เน€เธซเธกเธฒเธฐเธชเธณเธซเธฃเธฑเธเธเธนเนเธเธฅเธดเธ•เธเธฃเธฃเธเธธเธ เธฑเธ“เธ‘เนเธ—เธตเนเธ•เนเธญเธเธเธฒเธฃเนเธเธฅเธนเธเธฑเนเธเธเธธเธ“เธ เธฒเธเธชเธนเธเนเธเธฃเธฒเธเธฒเธ—เธตเนเน€เธซเธกเธฒเธฐเธชเธก</p>', '<p>The HL020 plastic spout cap with a 2mm inner diameter is crafted from premium PE material, delivering precise liquid dispensing for cosmetic and beauty packaging applications. This small-size spout is engineered for refill pouch packaging, liquid pouches, and beauty product containers requiring fine flow control. The PE material provides excellent chemical resistance and durability, making it compatible with serums, essences, an